{
  "name": "eGreetz",
  "description": "Create stunning cinematic video greetings with personalized voice and visuals.",
  "requestFramePermissions": [
    "microphone"
  ],
  "prompt": "Create a high-quality cinematic video greeting for a special occasion."
}

import {Video} from '@google/genai';

export enum AppState {
  IDLE,
  AUTH,
  LOADING,
  SUCCESS,
  ERROR,
  GALLERY
}

export enum Occasion {
  BIRTHDAY = 'Happy Birthday',
  CHRISTMAS = 'Merry Christmas',
  ANNIVERSARY = 'Happy Anniversary',
  NEW_YEARS = 'Happy New Years',
  PROMOTION = 'Congratulations on your Promotion',
  GRADUATION = 'Congratulations on your Graduation'
}

export enum GreetingTheme {
  BALLOONS = 'Balloons dropping',
  CHAMPAGNE = 'Champagne popping',
  FIREWORKS = 'Fireworks',
  NOISE_MAKERS = 'Noise makers'
}

export enum VoiceGender {
  MALE_TENOR = 'Male (Tenor)',
  MALE_BASS = 'Male (Bass)',
  FEMALE = 'Female'
}

export enum VeoModel {
  VEO_FAST = 'veo-3.1-fast-generate-preview',
  VEO = 'veo-3.1-generate-preview',
}

export enum AspectRatio {
  LANDSCAPE = '16:9',
  PORTRAIT = '9:16',
}

export enum Resolution {
  P720 = '720p',
  P1080 = '1080p',
}

export interface ImageFile {
  file: File;
  base64: string;
}

export interface GreetingRecord {
  id: string;
  userId: string;
  occasion: Occasion;
  message: string;
  theme: GreetingTheme;
  videoUrl: string;
  createdAt: number;
}

export interface GenerateGreetingParams {
  occasion: Occasion;
  message: string;
  theme: GreetingTheme;
  voice: VoiceGender;
  userPhoto: ImageFile | null;
  model: VeoModel;
  aspectRatio: AspectRatio;
}

import { initializeApp } from 'firebase/app';
import { getAuth, GoogleAuthProvider, signInWithPopup, signOut, User } from 'firebase/auth';
import { getFirestore, collection, addDoc, query, where, getDocs, deleteDoc, doc, orderBy } from 'firebase/firestore';
import { GreetingRecord } from '../types';

// These should be provided via Render.com Environment Variables
const firebaseConfig = JSON.parse(process.env.VITE_FIREBASE_CONFIG || '{}');

const app = initializeApp(firebaseConfig);
export const auth = getAuth(app);
export const db = getFirestore(app);
const googleProvider = new GoogleAuthProvider();

export const loginWithGoogle = async () => {
  try {
    const result = await signInWithPopup(auth, googleProvider);
    return result.user;
  } catch (error) {
    console.error("Login failed", error);
    throw error;
  }
};

export const logout = () => signOut(auth);

export const saveGreeting = async (userId: string, greeting: Omit<GreetingRecord, 'id'>) => {
  return await addDoc(collection(db, 'greetings'), {
    ...greeting,
    userId
  });
};

export const getUserGreetings = async (userId: string): Promise<GreetingRecord[]> => {
  const q = query(
    collection(db, 'greetings'),
    where('userId', '==', userId),
    orderBy('createdAt', 'desc')
  );
  const snapshot = await getDocs(q);
  return snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as GreetingRecord));
};

export const deleteGreeting = async (greetingId: string) => {
  await deleteDoc(doc(db, 'greetings', greetingId));
};

import {
  GoogleGenAI,
  Modality,
  VideoGenerationReferenceImage,
  VideoGenerationReferenceType,
} from '@google/genai';
import { GenerateGreetingParams, VoiceGender } from '../types';

export const generateGreetingVideo = async (
  params: GenerateGreetingParams
): Promise<{ objectUrl: string; blob: Blob }> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  // Construct a cinematic prompt for Veo
  const cinematicPrompt = `
    A cinematic, high-quality holiday greeting video for ${params.occasion}.
    Visual Theme: ${params.theme}. 
    Atmosphere: Joyful, celebratory, 8k resolution, professional lighting.
    The video should feel personal and warm. 
    Context: ${params.message.substring(0, 200)}...
  `.trim();

  const config: any = {
    numberOfVideos: 1,
    resolution: '720p',
    aspectRatio: params.aspectRatio,
  };

  const payload: any = {
    model: params.model,
    prompt: cinematicPrompt,
    config: config,
  };

  if (params.userPhoto) {
    payload.config.referenceImages = [{
      image: {
        imageBytes: params.userPhoto.base64,
        mimeType: params.userPhoto.file.type,
      },
      referenceType: VideoGenerationReferenceType.ASSET,
    }];
  }

  let operation = await ai.models.generateVideos(payload);

  while (!operation.done) {
    await new Promise((resolve) => setTimeout(resolve, 10000));
    operation = await ai.operations.getVideosOperation({ operation: operation });
  }

  if (operation?.response?.generatedVideos?.[0]?.video?.uri) {
    const videoUri = operation.response.generatedVideos[0].video.uri;
    const res = await fetch(`${videoUri}&key=${process.env.API_KEY}`);
    if (!res.ok) throw new Error('Failed to fetch generated video');
    const blob = await res.blob();
    return { objectUrl: URL.createObjectURL(blob), blob };
  }

  throw new Error('Video generation failed');
};

export const generateGreetingVoice = async (text: string, voice: VoiceGender): Promise<string | null> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const voiceMap: Record<VoiceGender, string> = {
    [VoiceGender.MALE_TENOR]: 'Kore',
    [VoiceGender.MALE_BASS]: 'Puck',
    [VoiceGender.FEMALE]: 'Charon'
  };

  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text: `Say this greeting message warmly: ${text}` }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: {
            prebuiltVoiceConfig: { voiceName: voiceMap[voice] },
          },
        },
      },
    });

    const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
    return base64Audio ? `data:audio/pcm;base64,${base64Audio}` : null;
  } catch (e) {
    console.error("TTS failed", e);
    return null;
  }
};

import React, { useState, useEffect, useCallback } from 'react';
import { User } from 'firebase/auth';
import { auth, loginWithGoogle, logout, getUserGreetings, saveGreeting, deleteGreeting } from './services/firebase';
import { AppState, GenerateGreetingParams, GreetingRecord, Occasion, GreetingTheme, VoiceGender, VeoModel, AspectRatio } from './types';
import GreetingCreator from './components/GreetingCreator';
import GreetingGallery from './components/GreetingGallery';
import GreetingResult from './components/GreetingResult';
import LoadingIndicator from './components/LoadingIndicator';
import ApiKeyDialog from './components/ApiKeyDialog';
import { LogIn, LogOut, Plus, GalleryVertical } from 'lucide-react';
import { generateGreetingVideo } from './services/geminiService';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [appState, setAppState] = useState<AppState>(AppState.AUTH);
  const [greetings, setGreetings] = useState<GreetingRecord[]>([]);
  const [currentResult, setCurrentResult] = useState<{ url: string; params: GenerateGreetingParams } | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [showApiKeyDialog, setShowApiKeyDialog] = useState(false);

  useEffect(() => {
    const unsubscribe = auth.onAuthStateChanged(async (u) => {
      setUser(u);
      if (u) {
        setAppState(AppState.GALLERY);
        loadGreetings(u.uid);
      } else {
        setAppState(AppState.AUTH);
      }
    });
    return unsubscribe;
  }, []);

  const loadGreetings = async (uid: string) => {
    const data = await getUserGreetings(uid);
    setGreetings(data);
  };

  const handleGenerate = async (params: GenerateGreetingParams) => {
    if (window.aistudio) {
      if (!(await window.aistudio.hasSelectedApiKey())) {
        setShowApiKeyDialog(true);
        return;
      }
    }

    setIsLoading(true);
    setAppState(AppState.LOADING);
    try {
      const { objectUrl } = await generateGreetingVideo(params);

      if (user) {
        await saveGreeting(user.uid, {
          userId: user.uid,
          occasion: params.occasion,
          message: params.message,
          theme: params.theme,
          videoUrl: objectUrl,
          createdAt: Date.now()
        });
        loadGreetings(user.uid);
      }

      setCurrentResult({ url: objectUrl, params });
      setAppState(AppState.SUCCESS);
    } catch (e) {
      console.error(e);
      setAppState(AppState.GALLERY);
    } finally {
      setIsLoading(false);
    }
  };

  const handleDelete = async (id: string) => {
    if (window.confirm("Are you sure you want to delete this greeting?")) {
      await deleteGreeting(id);
      if (user) loadGreetings(user.uid);
    }
  };

  const handleApiKeyDialogContinue = async () => {
    setShowApiKeyDialog(false);
    if (window.aistudio) await window.aistudio.openSelectKey();
  };

  return (
    <div className="min-h-screen bg-[#0a0a0c] text-white flex flex-col font-sans">
      {showApiKeyDialog && <ApiKeyDialog onContinue={handleApiKeyDialogContinue} />}

      <header className="px-6 py-4 flex justify-between items-center border-b border-white/10 bg-black/40 backdrop-blur-md sticky top-0 z-50">
        <div className="flex items-center gap-2 cursor-pointer" onClick={() => user && setAppState(AppState.GALLERY)}>
          <div className="w-10 h-10 bg-gradient-to-br from-indigo-500 to-purple-600 rounded-xl flex items-center justify-center font-bold text-xl shadow-lg shadow-indigo-500/20">
            eG
          </div>
          <h1 className="text-2xl font-bold tracking-tight bg-gradient-to-r from-white to-gray-400 bg-clip-text text-transparent">
            eGreetz
          </h1>
        </div>

        <div className="flex items-center gap-4">
          {user ? (
            <>
              <button 
                onClick={() => setAppState(AppState.IDLE)}
                className="flex items-center gap-2 px-4 py-2 bg-indigo-600 rounded-full hover:bg-indigo-500 transition-all font-medium"
              >
                <Plus size={18} /> New Greeting
              </button>
              <button 
                onClick={logout}
                className="p-2 text-gray-400 hover:text-white transition-colors"
                title="Logout"
              >
                <LogOut size={20} />
              </button>
            </>
          ) : (
            <button 
              onClick={loginWithGoogle}
              className="flex items-center gap-2 px-6 py-2 bg-white text-black font-semibold rounded-full hover:bg-gray-200 transition-all"
            >
              <LogIn size={18} /> Login
            </button>
          )}
        </div>
      </header>

      <main className="flex-grow flex flex-col items-center p-6 w-full max-w-6xl mx-auto">
        {appState === AppState.AUTH && (
          <div className="flex-grow flex flex-col items-center justify-center text-center max-w-lg">
            <h2 className="text-5xl font-extrabold mb-6 leading-tight">Cinematic Greetings for Special Moments</h2>
            <p className="text-xl text-gray-400 mb-8">Personalize your wishes with high-end AI video and unique voices. Log in to start creating.</p>
            <button 
              onClick={loginWithGoogle}
              className="px-10 py-4 bg-indigo-600 rounded-2xl text-xl font-bold hover:bg-indigo-500 transition-all shadow-xl shadow-indigo-600/20"
            >
              Sign in with Google
            </button>
          </div>
        )}

        {appState === AppState.GALLERY && user && (
          <GreetingGallery 
            greetings={greetings} 
            onDelete={handleDelete} 
            onCreateNew={() => setAppState(AppState.IDLE)}
          />
        )}

        {appState === AppState.IDLE && (
          <GreetingCreator onGenerate={handleGenerate} />
        )}

        {appState === AppState.LOADING && <LoadingIndicator />}

        {appState === AppState.SUCCESS && currentResult && (
          <GreetingResult 
            result={currentResult} 
            onRestart={() => setAppState(AppState.IDLE)} 
            onGoGallery={() => setAppState(AppState.GALLERY)}
          />
        )}
      </main>

      <footer className="py-6 text-center text-gray-600 text-sm border-t border-white/5">
        &copy; {new Date().getFullYear()} eGreetz. Powered by Gemini & Veo.
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect } from 'react';
import { Occasion, GreetingTheme, VoiceGender, GenerateGreetingParams, ImageFile, VeoModel, AspectRatio } from '../types';
import { Mic, Upload, X, ChevronRight, Sparkles, Wand2 } from 'lucide-react';

interface Props {
  onGenerate: (params: GenerateGreetingParams) => void;
}

const GreetingCreator: React.FC<Props> = ({ onGenerate }) => {
  const [occasion, setOccasion] = useState<Occasion>(Occasion.BIRTHDAY);
  const [message, setMessage] = useState('');
  const [theme, setTheme] = useState<GreetingTheme>(GreetingTheme.BALLOONS);
  const [voice, setVoice] = useState<VoiceGender>(VoiceGender.FEMALE);
  const [photo, setPhoto] = useState<ImageFile | null>(null);
  const [isRecording, setIsRecording] = useState(false);

  const fileInputRef = useRef<HTMLInputElement>(null);

  const handlePhotoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = () => {
        setPhoto({ file, base64: (reader.result as string).split(',')[1] });
      };
      reader.readAsDataURL(file);
    }
  };

  const startSpeechRecognition = () => {
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (!SpeechRecognition) {
      alert("Your browser doesn't support speech recognition.");
      return;
    }

    const recognition = new SpeechRecognition();
    recognition.lang = 'en-US';
    recognition.onstart = () => setIsRecording(true);
    recognition.onend = () => setIsRecording(false);
    recognition.onresult = (event: any) => {
      const transcript = event.results[0][0].transcript;
      setMessage(prev => (prev + ' ' + transcript).trim());
    };
    recognition.start();
  };

  return (
    <div className="w-full max-w-3xl bg-[#111114] border border-white/10 rounded-3xl p-8 shadow-2xl animate-in fade-in slide-in-from-bottom-4 duration-500">
      <div className="mb-10">
        <h2 className="text-3xl font-bold mb-2 flex items-center gap-3">
          <Sparkles className="text-indigo-400" /> Create Your Greeting
        </h2>
        <p className="text-gray-400">Set the occasion and let AI bring your message to life.</p>
      </div>

      <div className="space-y-8">
        {/* Occasion */}
        <div>
          <label className="block text-sm font-medium text-gray-400 mb-3 uppercase tracking-wider">The Occasion</label>
          <div className="grid grid-cols-2 md:grid-cols-3 gap-3">
            {Object.values(Occasion).map(occ => (
              <button
                key={occ}
                onClick={() => setOccasion(occ)}
                className={`p-3 rounded-xl border text-sm transition-all text-left ${occasion === occ ? 'bg-indigo-600 border-indigo-500 text-white' : 'bg-white/5 border-white/10 text-gray-400 hover:bg-white/10'}`}
              >
                {occ}
              </button>
            ))}
          </div>
        </div>

        {/* Message */}
        <div>
          <div className="flex justify-between items-center mb-3">
            <label className="text-sm font-medium text-gray-400 uppercase tracking-wider">Your Message</label>
            <span className="text-xs text-gray-500">{message.split(/\s+/).filter(w => w.length > 0).length} / 1000 words</span>
          </div>
          <div className="relative">
            <textarea
              value={message}
              onChange={(e) => setMessage(e.target.value)}
              placeholder="What do you want to say?"
              className="w-full h-32 bg-white/5 border border-white/10 rounded-2xl p-4 focus:outline-none focus:ring-2 focus:ring-indigo-500 transition-all resize-none"
              maxLength={5000}
            />
            <button
              onClick={startSpeechRecognition}
              className={`absolute bottom-4 right-4 p-3 rounded-full transition-all ${isRecording ? 'bg-red-500 animate-pulse' : 'bg-white/10 hover:bg-white/20'}`}
              title="Speak your message"
            >
              <Mic size={20} />
            </button>
          </div>
        </div>

        {/* Personalization Grid */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
          {/* Photo */}
          <div>
            <label className="block text-sm font-medium text-gray-400 mb-3 uppercase tracking-wider">Your Photo (Optional)</label>
            {photo ? (
              <div className="relative w-full aspect-video rounded-2xl overflow-hidden border border-white/10 group">
                <img src={URL.createObjectURL(photo.file)} alt="Preview" className="w-full h-full object-cover" />
                <button 
                  onClick={() => setPhoto(null)}
                  className="absolute top-2 right-2 p-2 bg-black/60 rounded-full text-white opacity-0 group-hover:opacity-100 transition-opacity"
                >
                  <X size={16} />
                </button>
              </div>
            ) : (
              <button 
                onClick={() => fileInputRef.current?.click()}
                className="w-full aspect-video bg-white/5 border-2 border-dashed border-white/10 rounded-2xl flex flex-col items-center justify-center gap-3 text-gray-500 hover:text-white hover:bg-white/10 hover:border-indigo-500/50 transition-all"
              >
                <Upload size={32} />
                <span>Upload Profile Image</span>
              </button>
            )}
            <input ref={fileInputRef} type="file" className="hidden" accept="image/*" onChange={handlePhotoUpload} />
          </div>

          {/* Voice & Theme */}
          <div className="space-y-6">
            <div>
              <label className="block text-sm font-medium text-gray-400 mb-3 uppercase tracking-wider">Voice Character</label>
              <select 
                value={voice}
                onChange={(e) => setVoice(e.target.value as VoiceGender)}
                className="w-full bg-white/5 border border-white/10 rounded-xl p-3 focus:outline-none focus:ring-2 focus:ring-indigo-500"
              >
                {Object.values(VoiceGender).map(v => <option key={v} value={v} className="bg-[#111114]">{v}</option>)}
              </select>
            </div>
            <div>
              <label className="block text-sm font-medium text-gray-400 mb-3 uppercase tracking-wider">Background Scene</label>
              <div className="grid grid-cols-2 gap-2">
                {Object.values(GreetingTheme).map(t => (
                  <button
                    key={t}
                    onClick={() => setTheme(t)}
                    className={`p-2 rounded-lg border text-xs transition-all ${theme === t ? 'bg-indigo-600/20 border-indigo-500 text-indigo-400' : 'bg-white/5 border-white/10 text-gray-500'}`}
                  >
                    {t}
                  </button>
                ))}
              </div>
            </div>
          </div>
        </div>

        <button
          onClick={() => onGenerate({ occasion, message, theme, voice, userPhoto: photo, model: VeoModel.VEO_FAST, aspectRatio: AspectRatio.LANDSCAPE })}
          disabled={!message.trim()}
          className="w-full py-5 bg-gradient-to-r from-indigo-600 to-purple-600 rounded-2xl font-bold text-xl flex items-center justify-center gap-3 hover:shadow-2xl hover:shadow-indigo-500/30 transition-all active:scale-[0.98] disabled:opacity-50 disabled:cursor-not-allowed"
        >
          <Wand2 /> Generate Cinematic Greeting
        </button>
      </div>
    </div>
  );
};

export default GreetingCreator;

