import React, { useState, useEffect } from 'react';
import { type User } from '@firebase/auth';
import { auth, loginWithGoogle, logout, getUserGreetings, saveGreeting, deleteGreeting, isFirebaseEnabled, onAuthStateChangedListener } from './services/firebase';
import { AppState, GenerateGreetingParams, GreetingRecord, Occasion, GreetingTheme, VoiceGender, VeoModel, AspectRatio } from './types';
import GreetingCreator from './components/GreetingCreator';
import GreetingGallery from './components/GreetingGallery';
import GreetingResult from './components/GreetingResult';
import LoadingIndicator from './components/LoadingIndicator';
import ApiKeyDialog from './components/ApiKeyDialog';
import { LogIn, LogOut, Plus, AlertCircle } from 'lucide-react';
import { generateGreetingVideo } from './services/geminiService';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [appState, setAppState] = useState<AppState>(AppState.AUTH);
  const [greetings, setGreetings] = useState<GreetingRecord[]>([]);
  const [currentResult, setCurrentResult] = useState<{ url: string; params: GenerateGreetingParams } | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [showApiKeyDialog, setShowApiKeyDialog] = useState(false);
  const [firebaseError, setFirebaseError] = useState<string | null>(null);

  useEffect(() => {
    if (!isFirebaseEnabled()) {
      setFirebaseError("Firebase is currently in demo mode. Your greetings won't be saved to the cloud.");
      setAppState(AppState.IDLE);
      return;
    }

    const unsubscribe = onAuthStateChangedListener(async (u) => {
      setUser(u);

      if (u) {
        loadGreetings(u.uid);
        setAppState(prev => {
          if (prev === AppState.AUTH) return AppState.GALLERY;
          return prev;
        });
      } else {
        setAppState(AppState.AUTH);
      }
    });
    return unsubscribe;
  }, []);

  const loadGreetings = async (uid: string) => {
    if (!isFirebaseEnabled()) return;
    const data = await getUserGreetings(uid);
    setGreetings(data);
  };

  const handleGenerate = async (params: GenerateGreetingParams) => {
    if (window.aistudio) {
      const hasKey = await window.aistudio.hasSelectedApiKey();
      if (!hasKey) {
        setShowApiKeyDialog(true);
        return;
      }
    }

    setIsLoading(true);
    setAppState(AppState.LOADING);

    try {
      const { objectUrl } = await generateGreetingVideo(params);

      if (user && isFirebaseEnabled()) {
        try {
          await saveGreeting(user.uid, {
            userId: user.uid,
            occasion: params.occasion,
            message: params.message,
            theme: params.theme,
            videoUrl: objectUrl,
            createdAt: Date.now()
          });
          loadGreetings(user.uid);
        } catch (saveError) {
          console.error("Cloud save failed, but video was generated successfully:", saveError);
        }
      }

      setCurrentResult({ url: objectUrl, params });
      setAppState(AppState.SUCCESS);
    } catch (e: any) {
      console.error("Video Generation Error:", e);

      const errorMessage = e.message || "Unknown error";
      const isApiKeyError = errorMessage.toLowerCase().includes("api key") || 
                           errorMessage.includes("Requested entity was not found") ||
                           errorMessage.includes("not set") ||
                           errorMessage.includes("API Key is required");

      if (isApiKeyError && window.aistudio) {
        await window.aistudio.openSelectKey();
      } else if (isApiKeyError) {
        alert("Authentication Error: The Gemini API Key is missing or invalid. Please ensure it is correctly set in your Render.com environment variables.");
      } else {
        alert("Failed to generate greeting: " + errorMessage);
      }

      setAppState(AppState.IDLE);
    } finally {
      setIsLoading(false);
    }
  };

  const handleDelete = async (id: string) => {
    if (window.confirm("Are you sure you want to delete this greeting? This cannot be undone.")) {
      try {
        await deleteGreeting(id);
        if (user) loadGreetings(user.uid);
      } catch (error) {
        console.error("Delete failed:", error);
      }
    }
  };

  return (
    <div className="min-h-screen bg-[#0a0a0c] text-white flex flex-col font-sans selection:bg-indigo-500/30">
      {showApiKeyDialog && <ApiKeyDialog onContinue={() => { setShowApiKeyDialog(false); window.aistudio?.openSelectKey(); }} />}

      <header className="px-6 py-4 flex justify-between items-center border-b border-white/10 bg-black/40 backdrop-blur-md sticky top-0 z-50">
        <div 
          className="flex items-center gap-2 cursor-pointer group" 
          onClick={() => (user || !isFirebaseEnabled()) && setAppState(user ? AppState.GALLERY : AppState.IDLE)}
        >
          <div className="w-10 h-10 bg-gradient-to-br from-indigo-500 to-purple-600 rounded-xl flex items-center justify-center font-bold text-xl shadow-lg shadow-indigo-500/20 group-hover:scale-105 transition-transform">
            eG
          </div>
          <h1 className="text-2xl font-bold tracking-tight bg-gradient-to-r from-white to-gray-400 bg-clip-text text-transparent">
            eGreetz
          </h1>
        </div>

        <div className="flex items-center gap-4">
          {user ? (
            <>
              <button 
                onClick={() => setAppState(AppState.IDLE)}
                className="flex items-center gap-2 px-4 py-2 bg-indigo-600 rounded-full hover:bg-indigo-500 transition-all font-medium text-sm shadow-lg shadow-indigo-500/20"
              >
                <Plus size={16} /> New Greeting
              </button>
              <button 
                onClick={logout}
                className="p-2 text-gray-400 hover:text-white transition-colors"
                title="Logout"
              >
                <LogOut size={20} />
              </button>
            </>
          ) : isFirebaseEnabled() ? (
            <button 
              onClick={loginWithGoogle}
              className="flex items-center gap-2 px-6 py-2 bg-white text-black font-semibold rounded-full hover:bg-gray-200 transition-all text-sm"
            >
              <LogIn size={16} /> Login
            </button>
          ) : (
            <button 
              onClick={() => setAppState(AppState.IDLE)}
              className="flex items-center gap-2 px-6 py-2 bg-indigo-600 text-white font-semibold rounded-full hover:bg-indigo-500 transition-all text-sm"
            >
              <Plus size={16} /> Create Now
            </button>
          )}
        </div>
      </header>

      <main className="flex-grow flex flex-col items-center p-6 w-full max-w-6xl mx-auto">
        {firebaseError && (appState === AppState.IDLE || appState === AppState.AUTH) && (
          <div className="w-full max-w-3xl mb-6 p-4 bg-yellow-500/10 border border-yellow-500/20 rounded-2xl flex items-center gap-3 text-yellow-500 text-sm">
            <AlertCircle className="shrink-0" />
            <p>{firebaseError}</p>
          </div>
        )}

        {appState === AppState.AUTH && (
          <div className="flex-grow flex flex-col items-center justify-center text-center max-w-lg animate-in fade-in zoom-in duration-1000">
            <h2 className="text-5xl font-extrabold mb-6 leading-tight">Cinematic Greetings for Special Moments</h2>
            <p className="text-xl text-gray-400 mb-8">Personalize your wishes with high-end AI video and unique voices. Log in to start creating.</p>
            {isFirebaseEnabled() ? (
              <button 
                onClick={loginWithGoogle}
                className="px-10 py-4 bg-indigo-600 rounded-2xl text-xl font-bold hover:bg-indigo-500 transition-all shadow-xl shadow-indigo-600/20 hover:-translate-y-1"
              >
                Sign in with Google
              </button>
            ) : (
              <button 
                onClick={() => setAppState(AppState.IDLE)}
                className="px-10 py-4 bg-indigo-600 rounded-2xl text-xl font-bold hover:bg-indigo-500 transition-all shadow-xl shadow-indigo-600/20 hover:-translate-y-1"
              >
                Get Started
              </button>
            )}
          </div>
        )}

        {appState === AppState.GALLERY && user && (
          <GreetingGallery 
            greetings={greetings} 
            onDelete={handleDelete} 
            onCreateNew={() => setAppState(AppState.IDLE)}
          />
        )}

        <div className={(appState === AppState.IDLE) ? "w-full flex justify-center" : "hidden"}>
          <GreetingCreator onGenerate={handleGenerate} />
        </div>

        {appState === AppState.LOADING && <LoadingIndicator />}

        {appState === AppState.SUCCESS && currentResult && (
          <GreetingResult 
            result={currentResult} 
            onRestart={() => setAppState(AppState.IDLE)} 
            onGoGallery={() => setAppState(user ? AppState.GALLERY : AppState.IDLE)}
          />
        )}
      </main>

      <footer className="py-6 text-center text-gray-600 text-sm border-t border-white/5 w-full">
        <p>&copy; {new Date().getFullYear()} eGreetz. Powered by Gemini & Veo.</p>
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useRef } from 'react';
import { Occasion, GreetingTheme, VoiceGender, GenerateGreetingParams, ImageFile, VeoModel, AspectRatio } from '../types';
import { Mic, Upload, X, Sparkles, Wand2 } from 'lucide-react';

interface Props {
  onGenerate: (params: GenerateGreetingParams) => void;
}

const GreetingCreator: React.FC<Props> = ({ onGenerate }) => {
  const [occasion, setOccasion] = useState<Occasion>(Occasion.BIRTHDAY);
  const [message, setMessage] = useState('');
  const [theme, setTheme] = useState<GreetingTheme>(GreetingTheme.BALLOONS);
  const [voice, setVoice] = useState<VoiceGender>(VoiceGender.FEMALE);
  const [photo, setPhoto] = useState<ImageFile | null>(null);
  const [isRecording, setIsRecording] = useState(false);

  const fileInputRef = useRef<HTMLInputElement>(null);

  const handlePhotoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = () => {
        setPhoto({ file, base64: (reader.result as string).split(',')[1] });
      };
      reader.readAsDataURL(file);
    }
  };

  const startSpeechRecognition = () => {
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitRecognition;
    if (!SpeechRecognition) {
      alert("Your browser doesn't support speech recognition.");
      return;
    }

    const recognition = new SpeechRecognition();
    recognition.lang = 'en-US';
    recognition.onstart = () => setIsRecording(true);
    recognition.onend = () => setIsRecording(false);
    recognition.onresult = (event: any) => {
      const transcript = event.results[0][0].transcript;
      setMessage(prev => (prev + ' ' + transcript).trim());
    };
    recognition.start();
  };

  return (
    <div className="w-full max-w-4xl bg-gray-900 border border-gray-800 rounded-3xl p-8 md:p-12 shadow-2xl animate-in fade-in slide-in-from-bottom-4 duration-700">
      <div className="mb-8">
        <h2 className="text-3xl font-bold mb-2 flex items-center gap-2">
          <Sparkles className="text-indigo-400" /> Create Your Greeting
        </h2>
        <p className="text-gray-400">Set the occasion and let AI bring your message to life.</p>
      </div>

      <div className="space-y-8">
        <div>
          <label className="block text-sm font-semibold text-gray-400 mb-4 uppercase tracking-wider">The Occasion</label>
          <div className="grid grid-cols-2 md:grid-cols-3 gap-3">
            {Object.values(Occasion).map(occ => (
              <button
                key={occ}
                onClick={() => setOccasion(occ)}
                className={`px-4 py-3 rounded-xl border text-sm font-medium transition-all text-left ${occasion === occ ? 'bg-indigo-600 border-indigo-500 text-white' : 'bg-gray-800 border-gray-700 text-gray-400 hover:bg-gray-700'}`}
              >
                {occ}
              </button>
            ))}
          </div>
        </div>

        <div>
          <div className="flex justify-between items-center mb-2">
            <label className="text-sm font-semibold text-gray-400 uppercase tracking-wider">Your Message</label>
            <span className="text-xs text-gray-500">{message.length} / 1000 words</span>
          </div>
          <div className="relative">
            <textarea
              value={message}
              onChange={(e) => setMessage(e.target.value)}
              placeholder="What do you want to say?"
              className="w-full h-32 bg-gray-800 border border-gray-700 rounded-xl p-4 text-white placeholder-gray-500 focus:outline-none focus:ring-2 focus:ring-indigo-500 transition-all resize-none"
              maxLength={1000}
            />
            <button
              onClick={startSpeechRecognition}
              className={`absolute bottom-3 right-3 p-2 rounded-full transition-all ${isRecording ? 'bg-red-500 animate-pulse' : 'bg-gray-700 hover:bg-gray-600 text-gray-300'}`}
            >
              <Mic size={20} />
            </button>
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
          <div>
            <label className="block text-sm font-semibold text-gray-400 mb-4 uppercase tracking-wider">Your Photo (Optional)</label>
            {photo ? (
              <div className="relative w-full aspect-video rounded-2xl overflow-hidden border border-gray-700">
                <img src={URL.createObjectURL(photo.file)} alt="Preview" className="w-full h-full object-cover" />
                <button 
                  onClick={() => setPhoto(null)}
                  className="absolute top-2 right-2 p-1.5 bg-black/60 rounded-full text-white hover:bg-red-500 transition-colors"
                >
                  <X size={16} />
                </button>
              </div>
            ) : (
              <button 
                onClick={() => fileInputRef.current?.click()}
                className="w-full aspect-video bg-gray-800 border-2 border-dashed border-gray-700 rounded-2xl flex flex-col items-center justify-center gap-2 text-gray-500 hover:text-indigo-400 hover:bg-gray-800/50 transition-all"
              >
                <Upload size={32} />
                <span className="text-sm">Upload Profile Image</span>
              </button>
            )}
            <input ref={fileInputRef} type="file" className="hidden" accept="image/*" onChange={handlePhotoUpload} />
          </div>

          <div className="space-y-6">
            <div>
              <label className="block text-sm font-semibold text-gray-400 mb-2 uppercase tracking-wider">Voice Character</label>
              <select 
                value={voice}
                onChange={(e) => setVoice(e.target.value as VoiceGender)}
                className="w-full bg-gray-800 border border-gray-700 rounded-xl p-3 focus:outline-none focus:ring-2 focus:ring-indigo-500 text-white"
              >
                {Object.values(VoiceGender).map(v => <option key={v} value={v}>{v}</option>)}
              </select>
            </div>
            <div>
              <label className="block text-sm font-semibold text-gray-400 mb-2 uppercase tracking-wider">Background Scene</label>
              <div className="grid grid-cols-2 gap-2">
                {Object.values(GreetingTheme).map(t => (
                  <button
                    key={t}
                    onClick={() => setTheme(t)}
                    className={`px-3 py-2 rounded-lg border text-xs font-medium transition-all ${theme === t ? 'bg-indigo-600/20 border-indigo-500 text-indigo-400' : 'bg-gray-800 border-gray-700 text-gray-500 hover:bg-gray-700'}`}
                  >
                    {t}
                  </button>
                ))}
              </div>
            </div>
          </div>
        </div>

        <button
          onClick={() => onGenerate({ occasion, message, theme, voice, userPhoto: photo, model: VeoModel.VEO_FAST, aspectRatio: AspectRatio.LANDSCAPE })}
          disabled={!message.trim()}
          className="w-full py-4 bg-indigo-600 rounded-xl font-bold text-lg flex items-center justify-center gap-2 hover:bg-indigo-500 transition-all active:scale-[0.98] disabled:opacity-50 disabled:cursor-not-allowed shadow-xl shadow-indigo-600/20"
        >
          <Wand2 size={24} /> Generate Cinematic Greeting
        </button>
      </div>
    </div>
  );
};

export default GreetingCreator;

