            {Object.values(Occasion).map(occ => (
              <button
                key={occ}
                onClick={() => setOccasion(occ)}
                className={`px-5 py-4 rounded-xl border text-sm font-semibold transition-all text-left ${occasion === occ ? 'bg-blue-600 border-blue-500 text-white shadow-lg shadow-blue-600/20' : 'bg-[#1a1a1c] border-white/5 text-gray-400 hover:bg-gray-800'}`}
              >
                {occ}
              </button>
            ))}
          </div>
        </div>

        <div>
          <div className="flex justify-between items-center mb-3">
            <label className="text-xs font-bold text-gray-500 uppercase tracking-[0.2em]">Your Message</label>
            <span className="text-xs font-medium text-gray-600">{message.length} / 1000 words</span>
          </div>
          <div className="relative">
            <textarea
              value={message}
              onChange={(e) => setMessage(e.target.value)}
              placeholder="What do you want to say?"
              className="w-full h-40 bg-[#151517] border border-white/5 rounded-2xl p-6 text-white text-lg placeholder-gray-600 focus:outline-none focus:ring-2 focus:ring-blue-600 transition-all resize-none shadow-inner"
              maxLength={1000}
            />
            <button
              onClick={startSpeechRecognition}
              className={`absolute bottom-4 right-4 p-3 rounded-full transition-all shadow-xl ${isRecording ? 'bg-red-500 animate-pulse' : 'bg-gray-800 hover:bg-gray-700 text-gray-300'}`}
            >
              <Mic size={24} />
            </button>
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
          <div>
            <label className="block text-xs font-bold text-gray-500 mb-4 uppercase tracking-[0.2em]">Your Photo (Optional)</label>
            {photo ? (
              <div className="relative w-full aspect-video rounded-2xl overflow-hidden border border-white/5 group">
                <img src={URL.createObjectURL(photo.file)} alt="Preview" className="w-full h-full object-cover" />
                <button 
                  onClick={() => setPhoto(null)}
                  className="absolute top-3 right-3 p-2 bg-black/60 rounded-full text-white hover:bg-red-500 transition-colors"
                >
                  <X size={18} />
                </button>
              </div>
            ) : (
              <button 
                onClick={() => fileInputRef.current?.click()}
                className="w-full aspect-video bg-[#151517] border-2 border-dashed border-white/5 rounded-2xl flex flex-col items-center justify-center gap-3 text-gray-500 hover:text-blue-400 hover:bg-[#1a1a1c] transition-all"
              >
                <Upload size={40} />
                <span className="font-semibold text-sm">Upload Profile Image</span>
              </button>
            )}
            <input ref={fileInputRef} type="file" className="hidden" accept="image/*" onChange={handlePhotoUpload} />
          </div>

          <div className="space-y-8">
            <div>
              <label className="block text-xs font-bold text-gray-500 mb-3 uppercase tracking-[0.2em]">Voice Character</label>
              <select 
                value={voice}
                onChange={(e) => setVoice(e.target.value as VoiceGender)}
                className="w-full bg-[#151517] border border-white/5 rounded-xl p-4 focus:outline-none focus:ring-2 focus:ring-blue-600 text-white font-medium"
              >
                {Object.values(VoiceGender).map(v => <option key={v} value={v} className="bg-[#0d0d0f]">{v}</option>)}
              </select>
            </div>
            <div>
              <label className="block text-xs font-bold text-gray-500 mb-3 uppercase tracking-[0.2em]">Background Scene</label>
              <div className="grid grid-cols-2 gap-3">
                {Object.values(GreetingTheme).map(t => (
                  <button
                    key={t}
                    onClick={() => setTheme(t)}
                    className={`px-4 py-3 rounded-xl border text-[11px] font-bold transition-all tracking-wider uppercase ${theme === t ? 'bg-blue-600/10 border-blue-500 text-blue-400' : 'bg-[#151517] border-white/5 text-gray-600 hover:bg-[#1a1a1c]'}`}
                  >
                    {t}
                  </button>
                ))}
              </div>
            </div>
          </div>
        </div>

        <button
          onClick={() => onGenerate({ occasion, message, theme, voice, userPhoto: photo, model: VeoModel.VEO_FAST, aspectRatio: AspectRatio.LANDSCAPE })}
          disabled={!message.trim()}
          className="w-full py-6 bg-blue-600 rounded-2xl font-black text-xl flex items-center justify-center gap-4 hover:bg-blue-500 transition-all active:scale-[0.99] disabled:opacity-30 disabled:cursor-not-allowed shadow-[0_20px_40px_-10px_rgba(37,99,235,0.4)] text-white"
        >
          <Wand2 size={28} /> Generate Cinematic Greeting
        </button>
      </div>
    </div>
  );
};

