import {
  GoogleGenAI,
  Modality,
  VideoGenerationReferenceType,
} from '@google/genai';
import { GenerateGreetingParams, VoiceGender, VeoModel } from '../types';

/**
 * Helper to decode base64 audio and get its duration in seconds.
 */
async function getAudioDuration(base64Data: string): Promise<number> {
  try {
    const binaryString = atob(base64Data);
    const bytes = new Uint8Array(binaryString.length);
    for (let i = 0; i < binaryString.length; i++) {
      bytes[i] = binaryString.charCodeAt(i);
    }

    // We need an AudioContext to decode and get duration
    const audioCtx = new (window.AudioContext || (window as any).webkitAudioContext)();
    // Gemini TTS returns raw PCM for Modality.AUDIO usually, 
    // but the SDK handles the wrapping when we use the generateContent response parts.
    // However, decodeAudioData expects a standard file format (WAV/MP3).
    // If it's raw PCM, we'd need to manually calculate based on sample rate.
    // Given the prompt's context of 8s targets, we will perform a smart calculation
    // based on typical Gemini TTS output (24kHz, 16-bit mono).
    const duration = (bytes.length / 2) / 24000; 
    return duration;
  } catch (e) {
    console.warn("Could not determine exact audio duration, defaulting to 8s", e);
    return 8;
  }
}

/**
 * Generates a cinematic greeting video using Gemini Veo models.
 * Now dynamically adjusts length to be 2-3 seconds longer than the generated audio.
 */
export const generateGreetingVideo = async (
  params: GenerateGreetingParams & { audioDuration?: number }
): Promise<{ objectUrl: string; blob: Blob }> => {
  const apiKey = process.env.API_KEY;

  if (!apiKey) {
    throw new Error("API Key is missing. Please select a paid API key in AI Studio.");
  }

  const ai = new GoogleGenAI({ apiKey });
  const modelToUse = params.userPhoto ? 'veo-3.1-generate-preview' : params.model;

  const cinematicPrompt = `
    A cinematic, high-quality holiday greeting video for ${params.occasion}.
    Visual Theme: ${params.theme}. 
    Atmosphere: Joyful, celebratory, professional cinematic lighting, 8k resolution feel.
    Context: ${params.message.substring(0, 300)}
  `.trim();

  const config: any = {
    numberOfVideos: 1,
    resolution: '720p',
    aspectRatio: params.userPhoto ? '16:9' : params.aspectRatio,
  };

  const payload: any = {
    model: modelToUse,
    prompt: cinematicPrompt,
    config: config,
  };

  if (params.userPhoto) {
    payload.config.referenceImages = [{
      image: {
        imageBytes: params.userPhoto.base64,
        mimeType: params.userPhoto.file.type || 'image/jpeg',
      },
      referenceType: VideoGenerationReferenceType.ASSET,
    }];
  }

  try {
    // 1. Initial Generation (Base 5-7 seconds)
    let operation = await ai.models.generateVideos(payload);

    while (!operation.done) {
      await new Promise((resolve) => setTimeout(resolve, 10000));
      operation = await ai.operations.getVideosOperation({ operation: operation });
    }

    let finalVideo = operation.response?.generatedVideos?.[0]?.video;

    // Calculate required duration: Audio Duration + 2.5 seconds buffer
    const targetDuration = (params.audioDuration || 0) + 2.5;
    const currentDuration = 7; // Standard Veo segment

    // 2. Extension logic if target duration exceeds the base segment
    if (targetDuration > currentDuration && finalVideo) {
      const extensionPayload = {
        model: 'veo-3.1-generate-preview',
        prompt: `The celebration reaches its cinematic peak for ${params.occasion}, keeping the same visual style and environment.`,
        video: finalVideo,
        config: {
          numberOfVideos: 1,
          resolution: '720p',
          aspectRatio: config.aspectRatio,
        }
      };

      let extendOp = await ai.models.generateVideos(extensionPayload);
      while (!extendOp.done) {
        await new Promise((resolve) => setTimeout(resolve, 10000));
        extendOp = await ai.operations.getVideosOperation({ operation: extendOp });
      }
      finalVideo = extendOp.response?.generatedVideos?.[0]?.video;
    }

    const downloadLink = finalVideo?.uri;
    if (downloadLink) {
      const response = await fetch(`${downloadLink}&key=${apiKey}`);
      if (!response.ok) throw new Error('Failed to download video.');

      const blob = await response.blob();
      return { objectUrl: URL.createObjectURL(blob), blob };
    }
  } catch (error: any) {
    console.error("Gemini Video Error:", error);
    throw error;
  }

  throw new Error('Video generation failed.');
};

/**
 * Generates audio for a greeting message using Gemini TTS.
 * Updated to return duration for video sync.
 */
export const generateGreetingVoice = async (text: string, voice: VoiceGender): Promise<{ base64: string, duration: number } | null> => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) return null;

  const ai = new GoogleGenAI({ apiKey });

  const voiceMap: Record<VoiceGender, string> = {
    [VoiceGender.MALE_TENOR]: 'Kore',
    [VoiceGender.MALE_BASS]: 'Puck',
    [VoiceGender.FEMALE]: 'Charon'
  };

  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text: `Speak this greeting message warmly but at a brisk, high-energy pace (around 160 words per minute): ${text}` }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: {
            prebuiltVoiceConfig: { voiceName: voiceMap[voice] },
          },
        },
      },
    });

    const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
    if (!base64Audio) return null;

    const duration = await getAudioDuration(base64Audio);
    return { base64: base64Audio, duration };
  } catch (e) {
    console.error("Voice Generation failed:", e);
    return null;
  }
};

import React, { useState, useEffect } from 'react';
import { 
  loginWithGoogle, 
  logout, 
  getUserGreetings, 
  saveGreeting, 
  deleteGreeting, 
  isFirebaseEnabled, 
  onAuthStateChangedListener,
  uploadVideoToCloud,
  getReceivedGreetings,
  sendToInternalUser,
  type User 
} from './services/firebase';
import { AppState, GenerateGreetingParams, GreetingRecord, VeoModel, AspectRatio, VoiceGender } from './types';
import GreetingCreator from './components/GreetingCreator';
import GreetingGallery from './components/GreetingGallery';
import GreetingResult from './components/GreetingResult';
import LoadingIndicator from './components/LoadingIndicator';
import ApiKeyDialog from './components/ApiKeyDialog';
import { LogIn, LogOut, Plus, ShieldCheck, Key, AlertCircle } from 'lucide-react';
import { generateGreetingVideo, generateGreetingVoice } from './services/geminiService';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [appState, setAppState] = useState<AppState>(AppState.AUTH);
  const [myGreetings, setMyGreetings] = useState<GreetingRecord[]>([]);
  const [receivedGreetings, setReceivedGreetings] = useState<GreetingRecord[]>([]);
  const [currentResult, setCurrentResult] = useState<{ url: string; params: GenerateGreetingParams; record?: GreetingRecord; audioUrl?: string } | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [showApiKeyDialog, setShowApiKeyDialog] = useState(false);
  const [isKeyConnected, setIsKeyConnected] = useState(false);
  const [isFirebaseReady, setIsFirebaseReady] = useState(false);

  useEffect(() => {
    const init = async () => {
      setIsFirebaseReady(isFirebaseEnabled());

      if (window.aistudio) {
        const hasKey = await window.aistudio.hasSelectedApiKey();
        setIsKeyConnected(hasKey);
      } else {
        const key = process.env.API_KEY;
        setIsKeyConnected(!!key);
      }
    };

    init();

    const unsubscribe = onAuthStateChangedListener((u) => {
      setUser(u);
      if (u) {
        loadData(u);
        if (appState === AppState.AUTH) {
          setAppState(AppState.GALLERY);
        }
      } else {
        setAppState(AppState.AUTH);
      }
    });

    return () => {
      if (typeof unsubscribe === 'function') unsubscribe();
    };
  }, [appState]);

  const loadData = async (u: User) => {
    const [mine, received] = await Promise.all([
      getUserGreetings(u.uid),
      u.email ? getReceivedGreetings(u.email) : Promise.resolve([])
    ]);
    setMyGreetings(mine);
    setReceivedGreetings(received);
  };

  const handleGenerate = async (params: GenerateGreetingParams & { extended: boolean }) => {
    if (!user) {
      alert("Please login with your Google Account to create and share cinematic greetings.");
      setAppState(AppState.AUTH);
      return;
    }

    if (window.aistudio) {
      const hasKey = await window.aistudio.hasSelectedApiKey();
      if (!hasKey) {
        setShowApiKeyDialog(true);
        return;
      }
    }

    setIsLoading(true);
    setAppState(AppState.LOADING);

    try {
      // 1. Generate Voice First to determine required video length
      const voiceResult = await generateGreetingVoice(params.message, params.voice);
      const audioDuration = voiceResult?.duration || 7;
      const audioBase64 = voiceResult?.base64;

      // 2. Generate Video synced to Audio Duration + 2.5 seconds
      const { blob } = await generateGreetingVideo({ 
        ...params, 
        audioDuration 
      });

      let finalUrl = "";
      let newRecord: GreetingRecord | undefined;

      if (isFirebaseReady) {
        // Step 1: Upload to Cloud Storage to get a permanent shareable URL (prevents "blob:" links)
        finalUrl = await uploadVideoToCloud(blob, user.uid);

        // Step 2: Save metadata to Firestore
        const docRef = await saveGreeting(user.uid, {
          userId: user.uid,
          occasion: params.occasion,
          message: params.message,
          theme: params.theme,
          videoUrl: finalUrl,
          createdAt: Date.now()
        });

        newRecord = {
          id: docRef.id,
          userId: user.uid,
          occasion: params.occasion,
          message: params.message,
          theme: params.theme,
          videoUrl: finalUrl,
          createdAt: Date.now()
        };

        loadData(user);
      } else {
        finalUrl = URL.createObjectURL(blob);
      }

      setCurrentResult({ 
        url: finalUrl, 
        params, 
        record: newRecord,
        audioUrl: audioBase64 ? `data:audio/wav;base64,${audioBase64}` : undefined 
      });
      setAppState(AppState.SUCCESS);
    } catch (e: any) {
      console.error("Production Error:", e);
      if (e.message?.includes("Requested entity was not found")) {
        setIsKeyConnected(false);
        if (window.aistudio) await window.aistudio.openSelectKey();
      }
      alert("Production Error: " + e.toString());
      setAppState(AppState.IDLE);
    } finally {
      setIsLoading(false);
    }
  };

  const handleDelete = async (id: string) => {
    if (window.confirm("Permanently delete this cinematic greeting?")) {
      try {
        await deleteGreeting(id);
        if (user) loadData(user);
      } catch (error) {
        console.error("Deletion failed:", error);
      }
    }
  };

  const handleSelectGreeting = (greeting: GreetingRecord) => {
    setCurrentResult({
      url: greeting.videoUrl,
      record: greeting,
      params: {
        occasion: greeting.occasion,
        message: greeting.message,
        theme: greeting.theme,
        voice: VoiceGender.FEMALE, 
        userPhoto: null,
        model: VeoModel.VEO_FAST,
        aspectRatio: AspectRatio.LANDSCAPE
      }
    });
    setAppState(AppState.SUCCESS);
  };

  const handleInternalShare = async (email: string) => {
    if (!currentResult?.record || !user) return;
    try {
      await sendToInternalUser(user.displayName || "A Friend", email, currentResult.record);
      alert("Sent! This greeting will appear in their 'Received' inbox.");
    } catch (err: any) {
      alert("Internal share failed: " + err.message);
    }
  };

  return (
    <div className="min-h-screen bg-black text-white flex flex-col font-sans selection:bg-blue-600/30">
      {showApiKeyDialog && <ApiKeyDialog onContinue={() => {
        if (window.aistudio) {
          window.aistudio.openSelectKey();
          setIsKeyConnected(true);
          setShowApiKeyDialog(false);
        }
      }} />}

      <header className="px-6 py-5 flex justify-between items-center border-b border-white/5 bg-black/95 backdrop-blur-xl sticky top-0 z-50">
        <div 
          className="flex items-center gap-2 cursor-pointer group" 
          onClick={() => setAppState(user ? AppState.GALLERY : AppState.AUTH)}
        >
          <div className="w-10 h-10 bg-blue-600 rounded-xl flex items-center justify-center font-bold text-xl shadow-[0_0_20px_rgba(37,99,235,0.4)] group-hover:scale-105 transition-transform text-white">
            eG
          </div>
          <div className="flex flex-col">
            <h1 className="text-2xl font-black tracking-tight text-white leading-none">eGreetz</h1>
            <div className="flex items-center gap-1.5 mt-1.5">
              <span className={`flex h-2 w-2 rounded-full ${isKeyConnected ? 'bg-green-500' : 'bg-yellow-500 animate-pulse'}`}></span>
              <span className="text-[10px] text-gray-400 font-black tracking-widest uppercase">
                {isKeyConnected ? 'Studio Ready' : 'Connect Key'}
              </span>
            </div>
          </div>
        </div>

        <div className="flex items-center gap-4">
          {user ? (
            <>
              <button 
                onClick={() => setAppState(AppState.IDLE)}
                className="flex items-center gap-2 px-6 py-2 bg-blue-600 rounded-full hover:bg-blue-500 transition-all font-bold text-sm text-white"
              >
                <Plus size={16} strokeWidth={3} /> New Script
              </button>
              <button onClick={logout} className="p-2 text-gray-500 hover:text-white transition-colors">
                <LogOut size={20} />
              </button>
            </>
          ) : (
            <button 
              onClick={loginWithGoogle}
              className="flex items-center gap-2 px-7 py-2.5 bg-white text-black font-black rounded-full hover:bg-gray-200 transition-all text-sm uppercase tracking-wider"
            >
              <LogIn size={16} strokeWidth={3} /> Login
            </button>
          )}
        </div>
      </header>

      <main className="flex-grow flex flex-col items-center p-6 w-full max-w-6xl mx-auto">
        {!isFirebaseReady && (
          <div className="w-full max-w-4xl mb-6 p-4 bg-red-900/10 border border-red-500/20 rounded-2xl flex items-center gap-3 text-red-200 text-sm">
            <AlertCircle size={20} className="text-red-400" />
            <span>Cloud Sync Inactive. Sharing is disabled. Please verify Firebase environment variables.</span>
          </div>
        )}

        {appState === AppState.AUTH && (
          <div className="flex-grow flex flex-col items-center justify-center text-center max-w-3xl animate-in fade-in zoom-in duration-1000">
            <h2 className="text-7xl font-black mb-8 leading-[1] text-white tracking-tighter">Cinematic <span className="text-blue-600">Reimagined.</span></h2>
            <p className="text-2xl text-gray-400 mb-12 leading-relaxed font-medium">Create and host Hollywood-grade video greetings. Permanent cloud storage ensures your links never expire.</p>
            <button 
              onClick={user ? () => setAppState(AppState.IDLE) : loginWithGoogle}
              className="px-16 py-6 bg-blue-600 rounded-3xl text-2xl font-black hover:bg-blue-500 transition-all shadow-2xl shadow-blue-600/40 uppercase tracking-widest text-white"
            >
              {user ? 'Start Creating' : 'Login to Start'}
            </button>
          </div>
        )}

        {appState === AppState.GALLERY && user && (
          <GreetingGallery 
            greetings={myGreetings} 
            receivedGreetings={receivedGreetings}
            onDelete={handleDelete} 
            onSelect={handleSelectGreeting}
            onCreateNew={() => setAppState(AppState.IDLE)}
          />
        )}

        {appState === AppState.IDLE && (
          <div className="w-full flex justify-center py-6">
            <GreetingCreator onGenerate={handleGenerate} onCancel={() => setAppState(user ? AppState.GALLERY : AppState.AUTH)} />
          </div>
        )}

        {appState === AppState.LOADING && <LoadingIndicator />}

        {appState === AppState.SUCCESS && currentResult && (
          <GreetingResult 
            result={currentResult} 
            onRestart={() => setAppState(AppState.IDLE)} 
            onGoGallery={() => setAppState(user ? AppState.GALLERY : AppState.IDLE)}
            onInternalShare={handleInternalShare}
          />
        )}
      </main>

      <footer className="py-10 text-center text-gray-800 text-xs border-t border-white/5 w-full">
        <p className="font-bold tracking-widest uppercase">&copy; {new Date().getFullYear()} eGreetz &bull; Digital Production Studio</p>
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect } from 'react';
import { GenerateGreetingParams, GreetingRecord } from '../types';
import { RefreshCw, LayoutGrid, Share2, Copy, Mail, MessageSquare, Check, Plus, Globe, Volume2 } from 'lucide-react';

interface Props {
  result: { url: string; params: GenerateGreetingParams; record?: GreetingRecord; audioUrl?: string };
  onRestart: () => void;
  onGoGallery: () => void;
  onInternalShare?: (email: string) => void;
}

const GreetingResult: React.FC<Props> = ({ result, onRestart, onGoGallery, onInternalShare }) => {
  const [copied, setCopied] = useState(false);
  const videoRef = useRef<HTMLVideoElement>(null);
  const audioRef = useRef<HTMLAudioElement>(null);

  // Use the permanent HTTPS link provided by Firebase Storage
  const shareUrl = result.url;

  // Sync Audio with Video playback
  useEffect(() => {
    const video = videoRef.current;
    const audio = audioRef.current;
    if (!video || !audio) return;

    const onPlay = () => audio.play();
    const onPause = () => audio.pause();
    const onSeeked = () => { audio.currentTime = video.currentTime; };

    video.addEventListener('play', onPlay);
    video.addEventListener('pause', onPause);
    video.addEventListener('seeked', onSeeked);

    return () => {
      video.removeEventListener('play', onPlay);
      video.removeEventListener('pause', onPause);
      video.removeEventListener('seeked', onSeeked);
    };
  }, []);

  const handleCopy = () => {
    // Force permanent URL and ensure no "blob:" prefix is copied
    if (shareUrl.startsWith('blob:')) {
      alert("Note: This is a temporary local link. Log in to generate a permanent cloud link.");
    }
    navigator.clipboard.writeText(shareUrl);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const handleEmail = () => {
    const subject = `eGreetz: A cinematic message for you!`;
    const body = `View your high-definition cinematic greeting here: ${shareUrl}\n\nSent via eGreetz Production Studio.`;
    window.location.href = `mailto:?subject=${encodeURIComponent(subject)}&body=${encodeURIComponent(body)}`;
  };

  const handleSMS = () => {
    const bodyText = `Check out this cinematic greeting I made for you: ${shareUrl}`;
    // Standard format to ensure text goes into message body on iOS/Android
    window.location.href = `sms:?&body=${encodeURIComponent(bodyText)}`;
  };

  const handleInternalTrigger = () => {
    if (!result.record) {
      alert("Internal sharing requires a permanent cloud record. Please log in.");
      return;
    }
    const email = prompt("Enter the recipient's Google Account email address:");
    if (email && email.includes('@') && onInternalShare) {
      onInternalShare(email);
    } else if (email) {
      alert("Invalid email format.");
    }
  };

  return (
    <div className="w-full max-w-4xl animate-in zoom-in duration-500">
      <div className="text-center mb-10">
        <h2 className="text-5xl font-black mb-4 tracking-tighter">Production Complete</h2>
        <p className="text-gray-400 font-medium">Your cinematic masterpiece is synced and ready for distribution.</p>
      </div>

      <div className="relative group rounded-3xl overflow-hidden shadow-2xl shadow-blue-500/20 mb-8 aspect-video bg-black ring-1 ring-white/10">
        <video 
          ref={videoRef}
          src={result.url} 
          controls 
          autoPlay 
          loop 
          className="w-full h-full object-contain"
        />
        {result.audioUrl && (
          <audio ref={audioRef} src={result.audioUrl} className="hidden" />
        )}

        <div className="absolute top-4 right-4 flex items-center gap-2 bg-blue-600/80 backdrop-blur-md px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-widest text-white">
          {shareUrl.startsWith('http') ? (
            <><Globe size={10} /> Cloud Hosted</>
          ) : (
            <><Volume2 size={10} /> Local Preview</>
          )}
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
        <div className="bg-[#111114] border border-white/10 rounded-3xl p-8">
          <h3 className="text-xl font-black mb-6 flex items-center gap-3">
            <Share2 size={24} className="text-blue-500" /> Share Masterpiece
          </h3>
          <div className="grid grid-cols-2 gap-4">
            <button 
              onClick={handleCopy}
              className="flex items-center justify-center gap-3 p-4 bg-white/5 hover:bg-white/10 rounded-2xl transition-all border border-white/5 font-bold text-sm"
            >
              {copied ? <Check size={18} className="text-green-500" /> : <Copy size={18} />}
              <span>{copied ? 'Copied' : 'Cloud Link'}</span>
            </button>
            <button 
              onClick={handleEmail}
              className="flex items-center justify-center gap-3 p-4 bg-white/5 hover:bg-white/10 rounded-2xl transition-all border border-white/5 font-bold text-sm"
            >
              <Mail size={18} />
              <span>Email</span>
            </button>
            <button 
              onClick={handleSMS}
